body:
The following index definition example uses the
sample\_mflix.movies collection. The index definition indexes only the
`title` field as the `autocomplete` type to support search-as-you-type
queries against that field using the [autocomplete](autocomplete-ref)
operator. The index definition also specifies the following:

- Use the [standard analyzer](ref-standard-analyzer) analyzer to divide
  text values into terms based on word boundaries.

- Use the `edgeGram` tokenization strategy to index characters
  starting at the left side of the words .

- Index a minimum of `3` characters per indexed sequence.

- Index a maximum of `5` characters per indexed sequence.

- Include diacritic marks in the index and query text.

- Use the `stableTfl` [Score Details](fts-similarity-algorithms) to ensure consistent document scoring
  across all search nodes and replica set members.

```cpp
#include <iostream>

#include <bsoncxx/builder/basic/document.hpp>
#include <bsoncxx/json.hpp>
#include <mongocxx/client.hpp>
#include <mongocxx/instance.hpp>
#include <mongocxx/uri.hpp>

using bsoncxx::builder::basic::kvp;
using bsoncxx::builder::basic::make_document;

int main(){

    mongocxx::instance instance;
    mongocxx::uri uri("<connection-string>");
    mongocxx::client client(uri);

    auto db = client["sample_mflix"];
    auto collection = db["movies"];

    // instantiate a ``mongocxx::search_index_view`` on your collection
    auto siv = collection.search_indexes();

    {
        auto name = "default";
        auto definition = make_document(
            kvp("mappings", make_document(
                kvp("dynamic", false),
                kvp("fields", make_document(
                    kvp("title", make_document(
                        kvp("type", "autocomplete"),
                        kvp("analyzer", "lucene.standard"),
                        kvp("tokenization", "edgeGram"),
                        kvp("minGrams", 3),
                        kvp("maxGrams", 5),
                        kvp("foldDiacritics", false),
                        kvp("similarity", make_document(kvp("type", "stableTfl")))
                    ))
                ))
            ))
        );

        auto model = mongocxx::search_index_model(name, definition.view());

        // Create the search index
        auto result = siv.create_one(model);
        std::cout << "New index name: " << result << std::endl;
    }
}

